/* eslint-disable @typescript-eslint/no-explicit-any */
import { motion } from 'framer-motion';

import { useTransition } from '@react-spring/web';
import * as React from 'react';

import { extent } from 'd3-array';

import { genRandomNormalPoints } from '@visx/mock-data';
import { ParentSize } from '@visx/responsive';
import { scaleLinear } from '@visx/scale';

import SpringCircle from './SpringCircle';

type Item = {
  //
};

export type Props = {
  width: number;
  height: number;
  data?: Item[];
};

const Content = React.memo((props: Props) => {
  // eslint-disable-next-line
  const { width, height, data } = props;

  const [seed, setSeed] = React.useState(0);
  const [count, setCount] = React.useState(1);

  const points = React.useMemo(
    () =>
      genRandomNormalPoints(count, seed).map(([x, y], i) => ({
        key: i,
        x,
        y,
      })),
    [count, seed]
  );

  const xScale = React.useMemo(
    () =>
      scaleLinear({
        domain: extent(points.map(({ x }) => x)) as any,
        range: [0, width],
        nice: true,
        round: true,
      }),
    [width]
  );

  const yScale = React.useMemo(
    () =>
      scaleLinear({
        domain: extent(points.map(({ y }) => y)) as any,
        range: [0, height],
        nice: true,
        round: true,
      }),
    [height]
  );

  const transitions = useTransition(points, {
    from: { opacity: 0 },
    enter: { opacity: 1 },
    leave: { opacity: 0 },
    delay: 200,
    keys: (p) => p.key,
  });

  // console.log('Content', { points });
  return (
    <>
      <svg width={width} height={height}>
        <g>
          {points.map(({ x, y }, i) => (
            <motion.circle
              key={i}
              cx={xScale(x)}
              cy={yScale(y)}
              r={10}
              // animate={{ cx: xScale(x), cy: xScale(y) }}
            />
          ))}
        </g>
      </svg>
      <svg width={width} height={height}>
        <g>
          {points.map(({ x, y }, i) => (
            <SpringCircle
              key={i}
              cx={xScale(x)}
              cy={yScale(y)}
              r={10}
              // animate={{ cx: xScale(x), cy: xScale(y) }}
            />
          ))}
        </g>
      </svg>
      <svg width={width} height={height}>
        <g>
          {transitions(({ opacity }, { key, x, y }) => (
            <SpringCircle
              key={key}
              // style={{ opacity: opacity.get() }}
              style={{ opacity, cx: xScale(x), cy: yScale(y) } as any}
              cx={xScale(x)}
              cy={yScale(y)}
              r={10}
              // animate={{ cx: xScale(x), cy: xScale(y) }}
            />
          ))}
        </g>
      </svg>
      <button type="button" onClick={() => setSeed((prev) => prev + 1)}>
        Next
      </button>
      <button
        type="button"
        style={{ marginLeft: '1rem' }}
        onClick={() => setCount((prev) => prev + 1)}
      >
        Add
      </button>
    </>
  );
});

const Transition01 = React.memo(() => (
  <ParentSize>
    {({ width }) => <Content width={width} height={300} />}
  </ParentSize>
));

export default Transition01;
