import { animated, useSpring } from '@react-spring/web';
import * as React from 'react';

export type Props = React.SVGProps<SVGCircleElement>;

const SpringCircle = React.memo((props: Props) => {
  // eslint-disable-next-line @typescript-eslint/no-unused-vars, no-unused-vars
  const { style, cx, cy, ref, ...rest } = props;

  const stylePos = useSpring({ cx, cy });
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return <animated.circle style={{ ...style, ...stylePos } as any} {...rest} />;
});

export default SpringCircle;
